codeComparison.new:
// Good: smooth continuous movement
const keys = {};
document.addEventListener('keydown', function(e) {
  keys[e.key] = true;
});
document.addEventListener('keyup', function(e) {
  keys[e.key] = false;
});

// In the game loop (60 FPS):
function loop() {
  if (keys['ArrowLeft']) player.x -= 6;
  if (keys['ArrowRight']) player.x += 6;
  // Smooth — moves every frame while held!
}
